#include<bits/stdc++.h>
using namespace std;
long long pow10(int k) {
    long long res = 1;
    for (int i = 0; i < k; i++) res *= 10;
    return res;
}
long long die(long long x, long long d) {
	if (x == 0) {
		return 0;
	}
	return 10 * die(x - 1, d) + (d == 0 ? pow10( x - 1) : x);
}
long long ji0(long long num) {
	if (num < 0) return 0;
	string s = to_string(num);
	long long res = 0;
	int n = s.size();
	for (int i = 1; i < n; i++) {
		long long h = 0, lo = 0;
		for (int j = 0; j < i; j++) h = h*10 + s[j]-'0';
		for (int j = i+1; j < n; j++) lo = lo*10 + s[j]-'0';
		int l = n - i - 1;
		if (s[i] - '0' > 0) {
			res += h * pow10(l);
		} else {
			res += (h-1)*pow10(l) + lo + 1;
		}
	}
	return res;
}
int main() {
	string s;
	int xx;
	long long y;
	cin >>  xx >> y;
	long long l = 1, r = 1e18,cnt;
	while (l <= r) {
		long long ans = 0;
		s = to_string(l+(r-l)/2);
		ans = 0;
        if (xx == 0) {
			ans = ji0(l+(r-l)/2);
		}else{
		for (int i = 0; i < s.size(); i++) {
				if (s[i] - '0' < xx) ans += ((s[i] - '0') * die(s.size() - i - 1, 0));
				else if (s[i] - '0' > xx)ans += (((s[i] - '0') * die(s.size() - i - 1, 0)) + pow10(s.size() - i - 1));
				else {
					long long num = 0;
					for (int j = i + 1; j < s.size(); j++)
						num = num * 10 + s[j] - '0';
					ans += (s[i] - '0') * die(s.size() - i - 1, 0) + num + 1;
				}

		}}
		if(ans>y){
			r=l+(r-l)/2-1;
		}else{
			cnt=l+(r-l)/2;
			l=l+(r-l)/2+1;
		}
	}
	cout<<cnt;
}
